package update

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"time"
)

const (
	cacheTTL      = 24 * time.Hour
	errorRetryTTL = 5 * time.Minute
	cacheFileName = "last-update-check.json"
)

// Cache manages the update check cache file
type Cache struct {
	filePath string
	data     *CacheData
}

// NewCache creates a new Cache instance
func NewCache() *Cache {
	return &Cache{
		data: &CacheData{},
	}
}

// Load reads cache from disk
func (c *Cache) Load() error {
	// Get cache file path
	if c.filePath == "" {
		path, err := c.getCacheFilePath()
		if err != nil {
			return fmt.Errorf("failed to determine cache path: %w", err)
		}
		c.filePath = path
	}

	// Read file
	data, err := os.ReadFile(c.filePath)
	if err != nil {
		return err // Return raw error for os.IsNotExist check
	}

	// Parse JSON
	if err := json.Unmarshal(data, c.data); err != nil {
		return fmt.Errorf("failed to parse cache: %w", err)
	}

	return nil
}

// Save writes cache to disk
func (c *Cache) Save() error {
	// Get cache file path
	if c.filePath == "" {
		path, err := c.getCacheFilePath()
		if err != nil {
			return fmt.Errorf("failed to determine cache path: %w", err)
		}
		c.filePath = path
	}

	// Ensure directory exists
	dir := filepath.Dir(c.filePath)
	if err := os.MkdirAll(dir, 0755); err != nil {
		return fmt.Errorf("failed to create cache directory: %w", err)
	}

	// Marshal to JSON
	data, err := json.MarshalIndent(c.data, "", "  ")
	if err != nil {
		return fmt.Errorf("failed to marshal cache: %w", err)
	}

	// Write to file
	if err := os.WriteFile(c.filePath, data, 0644); err != nil {
		return fmt.Errorf("failed to write cache: %w", err)
	}

	return nil
}

// IsExpired checks whether the cache should be refreshed.
// Successful checks use the long TTL; failed checks retry sooner to avoid dogpiling.
func (c *Cache) IsExpired() bool {
	if c.data.LastCheck.IsZero() {
		return true // No check recorded
	}
	ttl := cacheTTL
	if c.data.CheckError != "" {
		ttl = errorRetryTTL
	}
	return time.Since(c.data.LastCheck) > ttl
}

// getCacheFilePath returns the cache file path following XDG Base Directory spec
func (c *Cache) getCacheFilePath() (string, error) {
	// Check XDG_CACHE_HOME first
	cacheDir := os.Getenv("XDG_CACHE_HOME")
	if cacheDir == "" {
		// Fall back to ~/.cache
		homeDir, err := os.UserHomeDir()
		if err != nil {
			return "", fmt.Errorf("failed to get home directory: %w", err)
		}
		cacheDir = filepath.Join(homeDir, ".cache")
	}

	return filepath.Join(cacheDir, "ddx", cacheFileName), nil
}

package update

import (
	"context"
	"fmt"
	"os"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/config"
)

// Checker handles update checking logic
type Checker struct {
	currentVersion string
	config         *config.NewConfig
	cache          *Cache
	result         *UpdateCheckResult
}

// NewChecker creates a new Checker instance
func NewChecker(version string, cfg *config.NewConfig) *Checker {
	cache := NewCache()
	// Try to load cache, but don't fail if it doesn't exist
	_ = cache.Load()

	return &Checker{
		currentVersion: version,
		config:         cfg,
		cache:          cache,
	}
}

// ShouldCheck returns true if an update check is needed
func (c *Checker) ShouldCheck() bool {
	// Check if disabled in config
	if c.config.UpdateCheck != nil && !c.config.UpdateCheck.Enabled {
		return false
	}

	// Check if cache is expired or missing
	if c.cache.IsExpired() {
		return true
	}

	// Check if version changed (binary was upgraded)
	if c.cache.data.CurrentVersion != "" && c.cache.data.CurrentVersion != c.currentVersion {
		return true
	}

	// Cache is valid and fresh
	return false
}

// CheckForUpdate performs an update check if needed
// Returns the result, which is also stored in c.result for later retrieval
func (c *Checker) CheckForUpdate(ctx context.Context) (*UpdateCheckResult, error) {
	// Check if disabled via env var (takes precedence)
	if os.Getenv("DDX_DISABLE_UPDATE_CHECK") == "1" {
		c.result = &UpdateCheckResult{
			UpdateAvailable: false,
			LatestVersion:   c.currentVersion,
			Error:           nil,
		}
		return c.result, nil
	}

	// If check not needed, return cached result — but re-verify the cached
	// answer is still valid for the current binary version. If the user
	// upgraded past the cached LatestVersion, the cache is stale.
	if !c.ShouldCheck() {
		updateAvailable := c.cache.data.UpdateAvailable
		if updateAvailable && c.cache.data.LatestVersion != "" {
			needsUpgrade, err := NeedsUpgrade(c.currentVersion, c.cache.data.LatestVersion)
			if err != nil || !needsUpgrade {
				updateAvailable = false
			}
		}
		c.result = &UpdateCheckResult{
			UpdateAvailable: updateAvailable,
			LatestVersion:   c.cache.data.LatestVersion,
			Error:           nil,
		}
		return c.result, nil
	}

	// Perform actual check
	result := &UpdateCheckResult{}

	// Fetch latest release from GitHub
	release, err := FetchLatestRelease()
	if err != nil {
		result.Error = fmt.Errorf("failed to fetch latest release: %w", err)
		c.result = result

		// Update cache with error
		c.cache.data.LastCheck = time.Now()
		c.cache.data.CurrentVersion = c.currentVersion
		c.cache.data.CheckError = err.Error()
		_ = c.cache.Save() // Ignore save errors

		return result, err
	}

	// Compare versions
	needsUpgrade, err := NeedsUpgrade(c.currentVersion, release.TagName)
	if err != nil {
		result.Error = fmt.Errorf("failed to compare versions: %w", err)
		c.result = result

		// Update cache with error
		c.cache.data.LastCheck = time.Now()
		c.cache.data.CurrentVersion = c.currentVersion
		c.cache.data.CheckError = err.Error()
		_ = c.cache.Save() // Ignore save errors

		return result, err
	}

	// Update result
	result.UpdateAvailable = needsUpgrade
	result.LatestVersion = release.TagName
	c.result = result

	// Update cache with successful check
	c.cache.data.LastCheck = time.Now()
	c.cache.data.CurrentVersion = c.currentVersion
	c.cache.data.LatestVersion = release.TagName
	c.cache.data.UpdateAvailable = needsUpgrade
	c.cache.data.CheckError = ""

	_ = c.cache.Save() // Ignore save errors

	return result, nil
}

// IsUpdateAvailable returns the result from the last check
func (c *Checker) IsUpdateAvailable() (bool, string, error) {
	if c.result == nil {
		return false, "", nil
	}
	return c.result.UpdateAvailable, c.result.LatestVersion, c.result.Error
}

package update

import (
	"encoding/json"
	"os"
	"path/filepath"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

func TestCache_NewCache(t *testing.T) {
	cache := NewCache()
	assert.NotNil(t, cache)
	assert.NotNil(t, cache.data)
}

func TestCache_Load_NoFile(t *testing.T) {
	// Given: No cache file exists
	tempDir := t.TempDir()
	cache := &Cache{
		filePath: filepath.Join(tempDir, "nonexistent", "cache.json"),
	}

	// When: Load is called
	err := cache.Load()

	// Then: Should return error (file not found)
	assert.Error(t, err)
	assert.True(t, os.IsNotExist(err))
}

func TestCache_SaveAndLoad(t *testing.T) {
	// Given: A cache with data
	tempDir := t.TempDir()
	cache := &Cache{
		filePath: filepath.Join(tempDir, "cache.json"),
		data: &CacheData{
			LastCheck:       time.Now(),
			CurrentVersion:  "v0.1.2",
			LatestVersion:   "v0.1.3",
			UpdateAvailable: true,
		},
	}

	// When: Save is called
	err := cache.Save()
	require.NoError(t, err)

	// And: Load is called from a new cache instance
	loadedCache := &Cache{
		filePath: filepath.Join(tempDir, "cache.json"),
		data:     &CacheData{},
	}
	err = loadedCache.Load()

	// Then: Data should match
	require.NoError(t, err)
	assert.Equal(t, cache.data.CurrentVersion, loadedCache.data.CurrentVersion)
	assert.Equal(t, cache.data.LatestVersion, loadedCache.data.LatestVersion)
	assert.Equal(t, cache.data.UpdateAvailable, loadedCache.data.UpdateAvailable)

	// Timestamps should be within 1 second (JSON serialization precision)
	assert.WithinDuration(t, cache.data.LastCheck, loadedCache.data.LastCheck, time.Second)
}

func TestCache_IsExpired_Fresh(t *testing.T) {
	// Given: A cache with recent timestamp
	cache := &Cache{
		data: &CacheData{
			LastCheck: time.Now().Add(-1 * time.Hour), // 1 hour ago
		},
	}

	// When: IsExpired is called
	expired := cache.IsExpired()

	// Then: Should not be expired
	assert.False(t, expired, "Cache should not be expired after 1 hour")
}

func TestCache_IsExpired_Old(t *testing.T) {
	// Given: A cache with old timestamp
	cache := &Cache{
		data: &CacheData{
			LastCheck: time.Now().Add(-25 * time.Hour), // 25 hours ago
		},
	}

	// When: IsExpired is called
	expired := cache.IsExpired()

	// Then: Should be expired
	assert.True(t, expired, "Cache should be expired after 25 hours")
}

func TestCache_IsExpired_Exactly24Hours(t *testing.T) {
	// Given: A cache at exactly 24 hours (minus a millisecond to avoid timing issues)
	cache := &Cache{
		data: &CacheData{
			LastCheck: time.Now().Add(-24*time.Hour + time.Millisecond),
		},
	}

	// When: IsExpired is called
	expired := cache.IsExpired()

	// Then: Should not be expired (24h is the limit, > 24h is expired)
	assert.False(t, expired, "Cache at exactly 24 hours should not be expired")
}

func TestCache_IsExpired_FailureBackoffFresh(t *testing.T) {
	cache := &Cache{
		data: &CacheData{
			LastCheck:  time.Now().Add(-1 * time.Minute),
			CheckError: "failed to fetch latest release",
		},
	}

	assert.False(t, cache.IsExpired(), "Recent failure should use short retry backoff")
}

func TestCache_IsExpired_FailureBackoffOld(t *testing.T) {
	cache := &Cache{
		data: &CacheData{
			LastCheck:  time.Now().Add(-6 * time.Minute),
			CheckError: "failed to fetch latest release",
		},
	}

	assert.True(t, cache.IsExpired(), "Old failure should be retried after short backoff")
}

func TestCache_Load_CorruptedFile(t *testing.T) {
	// Given: A corrupted cache file
	tempDir := t.TempDir()
	cacheFile := filepath.Join(tempDir, "cache.json")

	err := os.WriteFile(cacheFile, []byte("invalid json {{{"), 0644)
	require.NoError(t, err)

	cache := &Cache{
		filePath: cacheFile,
		data:     &CacheData{},
	}

	// When: Load is called
	err = cache.Load()

	// Then: Should return JSON parse error
	assert.Error(t, err)
	assert.Contains(t, err.Error(), "failed to parse cache")
}

func TestCache_Save_CreatesDirectory(t *testing.T) {
	// Given: Cache path in non-existent directory
	tempDir := t.TempDir()
	cacheDir := filepath.Join(tempDir, "nested", "cache")
	cacheFile := filepath.Join(cacheDir, "cache.json")

	cache := &Cache{
		filePath: cacheFile,
		data: &CacheData{
			LastCheck:      time.Now(),
			CurrentVersion: "v0.1.0",
		},
	}

	// When: Save is called
	err := cache.Save()

	// Then: Should create directory and file
	require.NoError(t, err)
	assert.FileExists(t, cacheFile)
}

func TestCache_GetCacheFilePath_XDGCompliance(t *testing.T) {
	// Given: XDG_CACHE_HOME environment variable set
	originalXDG := os.Getenv("XDG_CACHE_HOME")
	defer func() { _ = os.Setenv("XDG_CACHE_HOME", originalXDG) }()

	testCacheDir := t.TempDir()
	_ = os.Setenv("XDG_CACHE_HOME", testCacheDir)

	// When: getCacheFilePath is called
	cache := &Cache{}
	path, err := cache.getCacheFilePath()

	// Then: Should use XDG_CACHE_HOME
	require.NoError(t, err)
	assert.Contains(t, path, testCacheDir)
	assert.Contains(t, path, "ddx")
	assert.Contains(t, path, "last-update-check.json")
}

func TestCache_GetCacheFilePath_FallbackToHome(t *testing.T) {
	// Given: XDG_CACHE_HOME not set
	originalXDG := os.Getenv("XDG_CACHE_HOME")
	defer func() { _ = os.Setenv("XDG_CACHE_HOME", originalXDG) }()
	_ = os.Unsetenv("XDG_CACHE_HOME")

	// When: getCacheFilePath is called
	cache := &Cache{}
	path, err := cache.getCacheFilePath()

	// Then: Should fall back to ~/.cache/ddx/
	require.NoError(t, err)
	homeDir, _ := os.UserHomeDir()
	expectedPrefix := filepath.Join(homeDir, ".cache", "ddx")
	assert.Contains(t, path, expectedPrefix)
}

func TestCacheData_JSONSerialization(t *testing.T) {
	// Given: Cache data
	now := time.Now()
	data := &CacheData{
		LastCheck:       now,
		CurrentVersion:  "v0.1.2",
		LatestVersion:   "v0.1.3",
		UpdateAvailable: true,
		CheckError:      "",
	}

	// When: Serialize to JSON and back
	jsonBytes, err := json.Marshal(data)
	require.NoError(t, err)

	var loaded CacheData
	err = json.Unmarshal(jsonBytes, &loaded)

	// Then: Should match original
	require.NoError(t, err)
	assert.Equal(t, data.CurrentVersion, loaded.CurrentVersion)
	assert.Equal(t, data.LatestVersion, loaded.LatestVersion)
	assert.Equal(t, data.UpdateAvailable, loaded.UpdateAvailable)
	assert.WithinDuration(t, data.LastCheck, loaded.LastCheck, time.Second)
}

func TestCache_Load_PermissionDenied(t *testing.T) {
	if os.Getuid() == 0 {
		t.Skip("Test cannot run as root (permissions would be ignored)")
	}

	// Given: A cache file with no read permissions
	tempDir := t.TempDir()
	cacheFile := filepath.Join(tempDir, "cache.json")

	// Create file
	err := os.WriteFile(cacheFile, []byte(`{"last_check":"2025-01-01T00:00:00Z"}`), 0644)
	require.NoError(t, err)

	// Remove read permissions
	err = os.Chmod(cacheFile, 0000)
	require.NoError(t, err)
	defer func() { _ = os.Chmod(cacheFile, 0644) }() // Restore for cleanup

	cache := &Cache{
		filePath: cacheFile,

		filePath: cacheFile,
		data:     &CacheData{},
	}

	// When: Load is called
	err = cache.Load()

	// Then: Should return permission error
	assert.Error(t, err)
	assert.True(t, os.IsPermission(err))
}

func TestCache_Save_PermissionDenied(t *testing.T) {
	if os.Getuid() == 0 {
		t.Skip("Test cannot run as root (permissions would be ignored)")
	}

	// Given: A directory with no write permissions
	tempDir := t.TempDir()
	cacheDir := filepath.Join(tempDir, "readonly")

	err := os.Mkdir(cacheDir, 0755)
	require.NoError(t, err)

	// Remove write permissions
	err = os.Chmod(cacheDir, 0555)
	require.NoError(t, err)
	defer func() { _ = os.Chmod(cacheDir, 0755) }() // Restore for cleanup

	cache := &Cache{
		filePath: filepath.Join(cacheDir, "cache.json"),
		data: &CacheData{
			LastCheck: time.Now(),
		},
	}

	// When: Save is called
	err = cache.Save()

	// Then: Should return permission error
	assert.Error(t, err)
}

